using System.ClientModel;
using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

// ---------------------------------------------------------------------------
// Tool instances
// ---------------------------------------------------------------------------
var notebook = new Notebook();

// ---------------------------------------------------------------------------
// Build the chat client with automatic function-invocation
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(new ApiKeyCredential(apiKey))
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Register available tools
var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearchTool.SearchWeb),
        AIFunctionFactory.Create(WebSearchTool.ReadPage),
        AIFunctionFactory.Create(notebook.AddNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ],
};

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
Console.WriteLine($"\n🔍 Researching: {topic}\n");

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the topic
        the user provides and produce a well-structured summary.

        Follow this process:
        1. Search the web for information about the topic (2-3 varied queries).
        2. Read the most promising pages to gather detailed information.
        3. Save important findings as notes using the note-taking tool.
        4. After gathering enough information, retrieve all your notes.
        5. Produce a final, well-organized summary of your research with
           key findings, important details, and sources.

        Be thorough but concise. Cite sources where possible.
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}"),
];

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("─────────────────────────────────────────");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("─────────────────────────────────────────");
Console.WriteLine(response.Text);
Console.WriteLine("─────────────────────────────────────────");
Console.WriteLine($"\n📝 Notes taken: {notebook.Count}");
return 0;

