// Web Search Tool — uses Bing search via scraping or a fallback
// ═══════════════════════════════════════════════════════════════════════════
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    [Description("Search the web for a query and return a list of result titles and URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = ParseDuckDuckGoResults(html);
            if (results.Count == 0)
                return JsonSerializer.Serialize(new { message = "No results found.", query });

            return JsonSerializer.Serialize(results.Take(8));
        }
        catch (Exception ex)
        {
            return JsonSerializer.Serialize(new { error = ex.Message, query });
        }
    }

    [Description("Fetch and read the text content of a web page at the given URL.")]
    public static async Task<string> ReadPage(
        [Description("The full URL of the page to read")] string url)
    {
        Console.WriteLine($"  📄 Reading:   {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);

            // Truncate to keep context manageable
            const int maxLen = 6000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n\n[Content truncated]";

            return text;
        }
        catch (Exception ex)
        {
            return $"Error reading page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseDuckDuckGoResults(string html)
    {
        var results = new List<SearchResult>();
        var span = html.AsSpan();

        // DuckDuckGo HTML results are in <a class="result__a"> tags
        const string marker = "class=\"result__a\"";
        int pos = 0;
        while (pos < span.Length && results.Count < 10)
        {
            var idx = html.IndexOf(marker, pos, StringComparison.Ordinal);
            if (idx < 0) break;

            // Find href
            var hrefStart = html.LastIndexOf("href=\"", idx, Math.Min(idx, 200), StringComparison.Ordinal);
            string link = "";
            if (hrefStart >= 0)
            {
                hrefStart += 6;
                var hrefEnd = html.IndexOf('"', hrefStart);
                if (hrefEnd > hrefStart)
                    link = html[hrefStart..hrefEnd];
            }

            // Find title text between > and </a>
            var titleStart = html.IndexOf('>', idx) + 1;
            var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.Ordinal);
            var title = titleStart > 0 && titleEnd > titleStart
                ? StripHtml(html[titleStart..titleEnd]).Trim()
                : "";

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(link))
            {
                // DuckDuckGo wraps links in a redirect — extract the actual URL
                if (link.Contains("uddg=", StringComparison.Ordinal))
                {
                    var uddgIdx = link.IndexOf("uddg=", StringComparison.Ordinal) + 5;
                    var ampIdx = link.IndexOf('&', uddgIdx);
                    link = ampIdx > 0
                        ? Uri.UnescapeDataString(link[uddgIdx..ampIdx])
                        : Uri.UnescapeDataString(link[uddgIdx..]);
                }

                results.Add(new SearchResult(title, link));
            }

            pos = idx + marker.Length;
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks then tags, decode entities
        var text = System.Text.RegularExpressions.Regex.Replace(
            html, @"<(script|style)[^>]*>[\s\S]*?</\1>", " ",
            System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
        return text.Trim();
    }

    private record SearchResult(string Title, string Url);
}

