// Note-Taking Tool — stores research notes in memory
// ═══════════════════════════════════════════════════════════════════════════
class Notebook
{
    private readonly List<Note> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research note with a title and content. Use this to record important findings.")]
    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("The note content / finding")] string content,
        [Description("Source URL if applicable")] string? source = null)
    {
        var note = new Note(title, content, source, DateTime.UtcNow);
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return JsonSerializer.Serialize(new { status = "saved", index = _notes.Count, title });
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return JsonSerializer.Serialize(new { message = "No notes saved yet." });

        Console.WriteLine($"  📖 Retrieved {_notes.Count} note(s)");
        return JsonSerializer.Serialize(_notes);
    }

    private record Note(string Title, string Content, string? Source, DateTime SavedAt);
}

